class PIIFreeSignature(dspy.Signature):
    def __post_init__(self):
        super().__post_init__()
        self.assertions = [
            lambda x: len(re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', str(x))) == 0,
            lambda x: 'XXX-XX-' not in str(x)
        ]

class SafeResponse(PIIFreeSignature):
    '''Return response without any PII'''
    response = dspy.OutputField()

