import re

def redact_pii(text: str) -> str:
    patterns = {
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
        r'\b\d{3}-?\d{2}-?\d{4}\b': '[SSN]',
        r'\b(?:\+?1[-.]?)?(?:\(?[0-9]{3}\)?)[-._]?[0-9]{3}[-._]?[0-9]{4}\b': '[PHONE]'
    }
    for pattern, replacement in patterns.items():
        text = re.sub(pattern, replacement, text, flags=re.IGNORECASE)
    return text

class PIIRedactedSignature(dspy.Signature):
    def forward(self, **kwargs):
        result = super().forward(**kwargs)
        result.response = redact_pii(result.response)
        return result

class SafeCustomerResponse(PIIRedactedSignature):
    '''Provide customer info without PII'''
    customer_query: str = dspy.InputField()
    response: str = dspy.OutputField(desc='Redacted response')

class StrictPIIAssertion(dspy.Assert):
    def __init__(self):
        self.pii_patterns = [
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
            r'\b\d{3}-\d{2}-\d{4}\b'
        ]

    def __call__(self, example):
        output = str(example.completions)
        for pattern in self.pii_patterns:
            if re.search(pattern, output, re.IGNORECASE):
                raise dspy.AssertionError(f'PII detected: {re.findall(pattern, output, re.IGNORECASE)}')
        return True

